+        ],
+        {
+          timeoutMs: 5_000,
+          env: { CLAWDBOT_TEST_ENV: "ok" },
+        },
+      );
+
+      expect(result.code).toBe(0);
+      expect(result.stdout).toBe("base|ok");
+    } finally {
+      if (previous === undefined) {
+        delete process.env.CLAWDBOT_BASE_ENV;
+      } else {
+        process.env.CLAWDBOT_BASE_ENV = previous;
+      }
+    }
